// apiKeyCountLabel renders the panel-header count, singularising for one key.
func apiKeyCountLabel(n int) string {
	if n == 1 {
		return "1 key"
	}
	return fmt.Sprintf("%d keys", n)
}

// revokeKey returns the data-on:click action that confirms, then DELETEs the key.
// The key name is user-supplied free text, so every interpolated value is
// JSON-encoded into a JS string literal: HTML escaping alone does not protect a
// JavaScript-attribute context (the DOM reverses it before datastar evaluates the
// expression), so a name containing quotes could otherwise break out and inject.
func revokeKey(uid, name, token string) string {
	nameJSON, _ := json.Marshal(name)
	uidJSON, _ := json.Marshal(uid)
	tokenJSON, _ := json.Marshal(token)
	return fmt.Sprintf(
		"if(!confirm('Revoke '+%s+'? Anything using this key stops working immediately.')) return; @delete('/app/settings/apikeys/'+%s, {headers: {'X-CSRF-Token': %s}})",
		nameJSON, uidJSON, tokenJSON,
	)
}

// changePassword returns the data-on:click action that guards the new/confirm
// match client-side, then POSTs the change.
func changePassword(token string) string {
	return fmt.Sprintf(
		"if($newPassword !== $confirmPassword){alert('New passwords do not match');return} @post('/app/settings/password', {headers: {'X-CSRF-Token': '%s'}})",
		token,
	)
}

// settingsSignals builds the page-level datastar signal object for the settings
// page. The defaultScanFrequency signal is pre-filled with the tenant's current
// default so the select renders with the right option pre-selected; the notify
// toggles are pre-filled so the checkboxes render in their current state.
func settingsSignals(props SettingsPageProps) string {
	freq := props.DefaultScanFrequency
	if freq == "" {
		freq = "daily"
	}
	return fmt.Sprintf(
		`{"newKeyName":"","currentPassword":"","newPassword":"","confirmPassword":"","defaultScanFrequency":"%s","notifyDailyDigest":%t,"notifyHighImpact":%t,"notifyHighImpactAlerts":%t,"notifyOptOut":%t}`,
		freq, props.NotifyDailyDigest, props.NotifyHighImpact, props.NotifyHighImpactAlerts, props.NotifyOptOut,
	)
}

